import {
  Paper,
  Table,
  TableBody,
  TableContainer,
  TableHead,
} from "@mui/material";

import { useTT } from "../../useTT.ts";
import { CashflowTableCategorySection } from "./CashflowTableCategorySection.tsx";
import { CashflowTableFinalBalanceRow } from "./CashflowTableFinalBalanceRow.tsx";
import { CashflowTableHeader } from "./CashflowTableHeader.tsx";
import { CashflowTableNetBalanceRow } from "./CashflowTableNetBalanceRow.tsx";

/**
 * Main cashflow table component.
 *
 * Layout (top to bottom):
 * 1. Header
 * 2. Income section header (expandable) + income categories
 * 3. Costs section header (expandable) + cost categories
 * 4. Net Balance
 * 5. Final Balance
 *
 * Features:
 * - Collapsible Income and Costs sections with totals
 * - Dynamically renders all periods returned by the API
 * - Full content height (page scrolls instead of table)
 */
export function CashflowTable() {
  const { tt } = useTT();

  return (
    <TableContainer component={Paper}>
      <Table
        sx={{ tableLayout: "fixed", borderCollapse: "separate" }}
        aria-label={tt("cashflowTable.accessibility.tableLabel")}
      >
        <TableHead>
          <CashflowTableHeader />
        </TableHead>

        <TableBody>
          <CashflowTableCategorySection variant="income" />
        </TableBody>
        <TableBody>
          <CashflowTableCategorySection variant="costs" />
        </TableBody>

        <TableBody>
          <CashflowTableNetBalanceRow />
          <CashflowTableFinalBalanceRow />
        </TableBody>
      </Table>
    </TableContainer>
  );
}

import { IconArrowUpRight } from "@dfp/react-icons";

import { useTT } from "../../useTT.ts";
import {
  CashflowCategory,
  CashflowCategoryDataRow,
  CashflowCategoryHeader,
  CashflowCategoryHeaderIcon,
  CashflowCategoryHeaderTitle,
  CashflowCategoryRows,
  CashflowCategoryTrigger,
  CashflowTableSummaryValueCell,
  useCashflowTable,
} from "./components/index.ts";

/**
 * Income category breakdown with collapsible section.
 *
 * Structure:
 * - Income section header (with total, expandable)
 *   - Income category rows (indented)
 */
export function CashflowTableIncomeCategories() {
  const { data, categoryFilter, allCategories, currency } = useCashflowTable();
  const { tt } = useTT();

  return (
    <CashflowCategory>
      <CashflowCategoryHeader>
        <CashflowCategoryHeaderTitle>
          <CashflowCategoryHeaderIcon sx={{ color: "success.main" }}>
            <IconArrowUpRight />
          </CashflowCategoryHeaderIcon>
          {tt("cashflowTable.rows.income")}
          <CashflowCategoryTrigger categoryType="income" />
        </CashflowCategoryHeaderTitle>

        {data?.periods.map((period, index) => (
          <CashflowTableSummaryValueCell
            key={period.id}
            value={period.income}
            currency={currency}
            columnIndex={index}
            dateFrom={period.dateFrom}
            isBold
            colorMode="none"
          />
        ))}
      </CashflowCategoryHeader>

      <CashflowCategoryRows>
        {categoryFilter.income.map((category) => (
          <CashflowCategoryDataRow
            key={category}
            allCategories={allCategories}
            category={category}
            direction="IN"
          />
        ))}
      </CashflowCategoryRows>
    </CashflowCategory>
  );
}

