import { useTT } from "../../useTT.ts";
import { CashflowTableCell } from "./CashflowTableCell.tsx";
import {
  CashflowTableSummaryRow,
  CashflowTableSummaryRowLabel,
  useCashflowTable,
} from "./components/index.ts";

export function CashflowTableNetBalanceRow() {
  const { tt } = useTT();
  const { data } = useCashflowTable();

  return (
    <CashflowTableSummaryRow>
      <CashflowTableSummaryRowLabel>
        {tt("cashflowTable.rows.netBalance")}
      </CashflowTableSummaryRowLabel>
      {data?.periods.map((period, index) => (
        <CashflowTableCell
          key={period.id}
          value={period.netBalance}
          columnIndex={index}
          dateFrom={period.dateFrom}
          isBold
          colorMode="balance"
        />
      ))}
    </CashflowTableSummaryRow>
  );
}

import { useTT } from "../../useTT.ts";
import {
  CashflowTableSummaryRow,
  CashflowTableSummaryRowLabel,
  CashflowTableSummaryValueCell,
  useCashflowTable,
} from "./components/index.ts";

export function CashflowTableFinalBalanceRow() {
  const { tt } = useTT();
  const { data, currency } = useCashflowTable();

  return (
    <CashflowTableSummaryRow>
      <CashflowTableSummaryRowLabel>
        {tt("cashflowTable.rows.finalBalance")}
      </CashflowTableSummaryRowLabel>
      {data?.periods.map((period, index) => (
        <CashflowTableSummaryValueCell
          key={period.id}
          value={period.finalBalance?.value ?? null}
          balanceQuality={period.finalBalance?.balanceQuality ?? null}
          currency={currency}
          columnIndex={index}
          dateFrom={period.dateFrom}
          isBold={true}
          colorMode="final"
        />
      ))}
    </CashflowTableSummaryRow>
  );
}

import type { BwCashflowModel } from "@dfp/bw-sdk-bw-cashflow";

import type { BalanceQuality } from "../../types/cashflow.types.ts";

export type CashFlowResponse =
  BwCashflowModel["getCashFlowAndBalanceStates"]["response"];
type CashFlowStates = NonNullable<CashFlowResponse["cashFlowStates"]>;
type SumArray = NonNullable<CashFlowStates["sumArray"]>;
type SumArrayItem = SumArray[number];
type IncomeCategorySum = NonNullable<SumArrayItem["incomeCategorySum"]>;
type ApiCategoryType = IncomeCategorySum[number]["category"];

export type CategoryType = ApiCategoryType;

/**
 * Represents a single period column in the cashflow table
 */
export type CashflowPeriod = {
  id: string;
  /** Date of the period (YYYY-MM-DD) */
  dateFrom: string;
  dateTo: string;
  /** Total income for this period */
  income: number;
  /** Total costs for this period */
  costs: number;
  /** Net change (income - costs) */
  netBalance: number;
  /** Final balance at end of period, including quality information when available */
  finalBalance: {
    value: number;
    balanceQuality: BalanceQuality;
  } | null;
  incomeCategories: Map<CategoryType, number>;
  costsCategories: Map<CategoryType, number>;
  progressPercentage?: number;
  transactionCount?: number;
};

/**
 * Complete data structure for the cashflow table
 */
export type CashflowTableData = {
  periods: CashflowPeriod[];
  granularity: "1D" | "1W" | "1M";
  categories: {
    income: CategoryType[];
    costs: CategoryType[];
  };
};

export type CategoryFilter = {
  income: CategoryType[];
  costs: CategoryType[];
};

export type CategoryFilterSection = "income" | "costs";

export type CategoryOption = {
  value: CategoryType;
  label: string;
};

export type CategoryFilterState = {
  categoryFilter: CategoryFilter;
  setCategoryFilter: (filter: CategoryFilter) => void;
  allCategories: CategoryOption[];
  allCategoryValues: CategoryType[];
  isFiltered: boolean;
  totalSelected: number;
  totalAvailable: number;
};

export type CashflowTableCellProps = {
  value: number;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  /** Optional progress percentage to display as a bar */
  progressPercentage?: number;
  /** Color mode for value display:
   * - "balance": red for negative, green for positive (Net Balance)
   * - "final": red for negative only, neutral for positive/zero (Final Balance)
   * - "none": always neutral color (Income, Costs, all categories)
   * Default: "none"
   */
  colorMode?: "balance" | "final" | "none";
  /** Optional click handler. When provided, replaces the default column toggle behavior. */
  onClick?: () => void;
};

import { IconArrowDownRight, IconArrowUpRight } from "@dfp/react-icons";

import { useTT } from "../../useTT.ts";
import { CashflowTableValueCell } from "./components/CashflowTableValueCell.tsx";
import {
  CashflowCategory,
  CashflowCategoryDataRow,
  CashflowCategoryHeader,
  CashflowCategoryHeaderIcon,
  CashflowCategoryHeaderTitle,
  CashflowCategoryRows,
  CashflowCategoryTrigger,
  useCashflowTable,
} from "./components/index.ts";
import type { CategoryType } from "./types/index.ts";

type CashflowTableCategorySectionProps = {
  variant: "income" | "costs";
};

const sectionPresets = {
  income: {
    titleKey: "cashflowTable.rows.income" as const,
    icon: IconArrowUpRight,
    iconColor: "success.main",
    categoryType: "income" as const,
    direction: "IN" as const,
    totalSelector: (period: { income: number }) => period.income,
    filterSelector: (categoryFilter: { income: CategoryType[] }) =>
      categoryFilter.income,
  },
  costs: {
    titleKey: "cashflowTable.rows.costs" as const,
    icon: IconArrowDownRight,
    iconColor: "error.main",
    categoryType: "costs" as const,
    direction: "OUT" as const,
    totalSelector: (period: { costs: number }) => period.costs,
    filterSelector: (categoryFilter: { costs: CategoryType[] }) =>
      categoryFilter.costs,
  },
};

export function CashflowTableCategorySection({
  variant,
}: CashflowTableCategorySectionProps) {
  const { data, categoryFilter, allCategories } = useCashflowTable();
  const { tt } = useTT();
  const preset = sectionPresets[variant];
  const Icon = preset.icon;

  return (
    <CashflowCategory>
      <CashflowCategoryHeader>
        <CashflowCategoryHeaderTitle>
          <CashflowCategoryHeaderIcon sx={{ color: preset.iconColor }}>
            <Icon />
          </CashflowCategoryHeaderIcon>
          {tt(preset.titleKey)}
          <CashflowCategoryTrigger categoryType={preset.categoryType} />
        </CashflowCategoryHeaderTitle>

        {data?.periods.map((period, index) => (
          <CashflowTableValueCell
            key={period.id}
            columnIndex={index}
            dateFrom={period.dateFrom}
            isBold
          >
            {preset.totalSelector(period)}
          </CashflowTableValueCell>
        ))}
      </CashflowCategoryHeader>

      <CashflowCategoryRows>
        {preset.filterSelector(categoryFilter).map((category: CategoryType) => (
          <CashflowCategoryDataRow
            key={category}
            allCategories={allCategories}
            category={category}
            direction={preset.direction}
          />
        ))}
      </CashflowCategoryRows>
    </CashflowCategory>
  );
}

